// Generates src/icons.ts from lucide-static (ISC, https://lucide.dev). Run via:
//   node scripts/gen-lucide-icons.mjs
// Inlines the WHOLE Lucide set as stroke-based SVG inner-markup so every icon is
// usable via {{icon "name"}} (the publisher only-used-ships the ones a page references)
// and the editor's icon picker can browse the full library. Re-run after a
// lucide-static upgrade, then commit the generated file.
import { readFileSync, writeFileSync, readdirSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';
import { createRequire } from 'node:module';

const require = createRequire(import.meta.url);
const pkgDir = dirname(require.resolve('lucide-static/package.json'));
const iconsDir = join(pkgDir, 'icons');
const tags = JSON.parse(readFileSync(join(pkgDir, 'tags.json'), 'utf8'));

/** Strip the license comment + the <svg …> wrapper, leaving the inner shapes; collapse whitespace. */
function innerMarkup(svg) {
  return svg
    .replace(/<!--[\s\S]*?-->/g, '') // license comment
    .replace(/<svg[\s\S]*?>/, '') // opening <svg …>
    .replace(/<\/svg>\s*$/, '') // closing </svg>
    .replace(/\s+/g, ' ') // collapse whitespace between/inside tags
    .replace(/>\s+</g, '><')
    .trim();
}

const names = readdirSync(iconsDir)
  .filter((f) => f.endsWith('.svg'))
  .map((f) => f.slice(0, -4))
  .sort();

const iconRows = names
  .map((name) => `  [${JSON.stringify(name)}, ${JSON.stringify(innerMarkup(readFileSync(join(iconsDir, `${name}.svg`), 'utf8')))}],`)
  .join('\n');

// Search keywords per icon (lucide's own tags) — lets the picker find "home" by "house" etc.
// Only emit a row when the icon actually has tags, to keep the map compact.
const tagRows = names
  .filter((name) => Array.isArray(tags[name]) && tags[name].length > 0)
  .map((name) => `  [${JSON.stringify(name)}, ${JSON.stringify(tags[name].join(' '))}],`)
  .join('\n');

const out = `// AUTO-GENERATED by scripts/gen-lucide-icons.mjs from lucide-static (ISC,
// https://lucide.dev). DO NOT EDIT BY HAND — re-run the generator to refresh.
// Each value is the inner markup of a 24x24, stroke-based ('currentColor') icon;
// the Icon block / {{sw-icon}} helper wraps it in an <svg>. Brand logos (trademarks)
// live separately in brand-icons.ts. The publisher only-used-ships referenced icons.
const ICONS = new Map<string, string>([
${iconRows}
]);

/** Lucide's search keywords per icon (icon name → space-joined synonyms), for the picker. */
const ICON_TAGS = new Map<string, string>([
${tagRows}
]);

/** Names of the built-in icons (for the editor's icon picker). */
export const ICON_NAMES: readonly string[] = [...ICONS.keys()];

/** Inner SVG markup for a built-in icon, or \`undefined\` if the name is unknown. */
export function iconBody(name: string): string | undefined {
  return ICONS.get(name);
}

/** Space-joined search synonyms for an icon (empty string when it has none). */
export function iconTags(name: string): string {
  return ICON_TAGS.get(name) ?? '';
}
`;

const dir = dirname(fileURLToPath(import.meta.url));
const target = join(dir, '..', 'src', 'icons.ts');
writeFileSync(target, out);
console.log(`wrote ${names.length} Lucide icons (${tagRows.split('\\n').length} with tags) to ${target}`);
